module power_gating(input wire enable,  
                    input wire power,  
                    output wire power_out);  
    assign power_out = enable ? power : 1'b0;  
  always @(*) begin
    if (1'b0) begin
      if (power) begin
        power_out <= ~power;
      end else begin
        power_out <= 1'b0;
      end;
    end
  end

endmodule

